import React, { useMemo, useEffect, useState, useCallback } from 'react';
import { useTable, useSortBy, usePagination } from 'react-table';
import AddProject from './AddProject'; // Adjust the import path as needed
import EditProject from './EditProject'; // Adjust the import path as needed
import './PurchaseFunc.css';

const ProjectFunc = ({ apiBaseUrl }) => {
  const [editingProject, setEditingProject] = useState(null);
  const [projects, setProjects] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [globalFilter, setGlobalFilter] = useState('');

  const fetchAPI = useCallback(async (url, options = {}) => {
    const authToken = sessionStorage.getItem('authToken');
    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        'Authorization': `Bearer ${authToken}`,
        'Content-Type': 'application/json',
      },
    });
    if (!response.ok) {
      const errorResponse = await response.json();
      throw new Error(errorResponse.message || `Error fetching ${url}`);
    }
    return response.json();
  }, []);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    try {
      const projectsResponse = await fetchAPI(`${apiBaseUrl}/projectsAPI`);
      setProjects(projectsResponse);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setIsLoading(false);
    }
  }, [fetchAPI, apiBaseUrl]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAddProject = useCallback(async (newProject) => {
    try {
      await fetchAPI(`${apiBaseUrl}/projectsAPI`, {
        method: 'POST',
        body: JSON.stringify(newProject),
      });
      fetchData();
    } catch (error) {
      console.error('Error adding project:', error);
    }
  }, [fetchData, apiBaseUrl, fetchAPI]);

  const handleDelete = useCallback(async (project) => {
    if (window.confirm('Are you sure you want to delete this project?')) {
      try {
        await fetchAPI(`${apiBaseUrl}/projectsAPI/${project.prid}`, {
          method: 'DELETE',
        });
        fetchData();
      } catch (error) {
        console.error('Error deleting project:', error);
      }
    }
  }, [fetchData, apiBaseUrl, fetchAPI]);

  const handleEdit = useCallback((project) => {
    setEditingProject(project);
  }, []);

  const handleUpdateStatus = useCallback(async (project, newStatus) => {
    // Assuming project has an ID field to uniquely identify it
    const updatedProject = { ...project, status: newStatus };
    try {
      await fetchAPI(`${apiBaseUrl}/projectsAPI/${project.prid}`, {
        method: 'PUT',
        body: JSON.stringify(updatedProject),
      });
      fetchData();
    } catch (error) {
      console.error('Error updating the project status:', error);
    }
  }, [fetchData, apiBaseUrl, fetchAPI]);

  const handleUpdate = useCallback(async (project) => {
    try {
      await fetchAPI(`${apiBaseUrl}/projectsAPI/${project.prid}`, {
        method: 'PUT',
        body: JSON.stringify(project),
      });
      fetchData();
    } catch (error) {
      console.error('Error updating the project:', error);
    } finally {
      setEditingProject(null);
    }
  }, [fetchData, apiBaseUrl, fetchAPI]);

  const handleCancel = useCallback(() => {
    setEditingProject(null);
  }, []);

  const { projectsInProgress, projectsCompleted } = useMemo(() => {
    const filtered = projects.filter(project => 
      project.name.toLowerCase().includes(globalFilter.toLowerCase()) ||
      project.description.toLowerCase().includes(globalFilter.toLowerCase())
    );
    return {
      projectsInProgress: filtered.filter(p => p.status === 0),
      projectsCompleted: filtered.filter(p => p.status === 1),
    };
  }, [projects, globalFilter]);


  const columns = useMemo(() => [
    { Header: 'ID', accessor: 'prid' },
    { Header: 'Name', accessor: 'name' },
    { Header: 'Description', accessor: 'description' },
    { Header: 'Projected Material Cost', accessor: 'prmatcost' },
    { Header: 'Projected Labor Cost', accessor: 'prlabcost' },
    { Header: 'Sale', accessor: 'sale' },
    { Header: 'Real Material Cost', accessor: 'realmatcostNumeric' },
    { Header: 'Real Labor Cost', accessor: 'reallabcost' },
    { Header: 'Total Cost', accessor: 'totalcost' },
    {
      Header: 'Status',
      accessor: 'status',
      Cell: ({ row }) => {
        // Assuming 'status' field directly indicates completion (1 for completed, 0 for in progress)
        const isCompleted = row.original.status === 1;
        return (
          <label>
            Completed:
            <input
              type="checkbox"
              checked={isCompleted}
              onChange={() => handleUpdateStatus(row.original, isCompleted ? 0 : 1)}
            />
          </label>
        );
      },
  },
    {
      Header: 'Actions',
      id: 'actions',
      accessor: (row) => row,
      Cell: ({ value }) => (
        <div>
          <button onClick={() => handleEdit(value)}>Edit</button>
          <button onClick={() => handleDelete(value)}>Delete</button>
        </div>
      ),
    },
  ], [handleEdit, handleDelete,handleUpdateStatus]);

  const Table = ({ data, title }) => {
    const { getTableProps, getTableBodyProps, headerGroups, prepareRow, rows } = useTable(
      { columns, data },
      useSortBy,
      usePagination
    );

    return (
      <>
        <h2>{title}</h2>
        <table {...getTableProps()}>
          {/* Table structure */}
        </table>
      </>
    );
  };

  if (isLoading) return <div>Loading...</div>;

  return (
    <div className='container'>
      <AddProject onAddProject={handleAddProject} />
      <input
        type="text"
        value={globalFilter}
        onChange={e => setGlobalFilter(e.target.value)}
        placeholder="Search projects..."
      />
      <Table data={projectsInProgress} title="Projects In Progress" />
      <Table data={projectsCompleted} title="Projects Completed" />
      {editingProject && <EditProject project={editingProject} onCancel={() => setEditingProject(null)} />}
    </div>
  );
};

export default ProjectFunc;
